import { inject, Injectable, OnDestroy } from "@angular/core";
import { AuthService } from "./auth.service";
import { BehaviorSubject, Observable, map, shareReplay, catchError, of, from, switchMap, Subject, takeUntil } from "rxjs";
import { SupabaseService } from "./supabase.service";
import { LoadingService } from "./loading.service";

@Injectable({ providedIn: 'root' })
export abstract class BaseService<T> implements OnDestroy {
  protected supabaseService = inject(SupabaseService);
  protected authService = inject(AuthService);
  protected loadingService = inject(LoadingService);
  private destroy$ = new Subject<void>();

  protected dataSubject = new BehaviorSubject<T[]>([]);
  public data$ = this.dataSubject.asObservable().pipe(shareReplay(1));

  protected loadingSubject = new BehaviorSubject<boolean>(false);
  public loading$ = this.loadingSubject.asObservable();

  protected errorSubject = new BehaviorSubject<string | null>(null);
  public error$ = this.errorSubject.asObservable();

  protected abstract getTableName(): string;

constructor() {
  this.authService.activeRestaurantId$
    .pipe(
      takeUntil(this.destroy$),
      switchMap(() => from(this.loadData()))
    )
    .subscribe();
}

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
    this.dataSubject.complete();
    this.loadingSubject.complete();
    this.errorSubject.complete();
  }

  /**
   * Esegue una query Supabase attivando il loader globale.
   * Accetta qualsiasi oggetto "thenable" (Promise o PostgrestBuilder).
   */
  protected async run<R>(query: PromiseLike<{ data: R | null; error: any }>): Promise<{ data: R | null; error: any }> {
    this.loadingService.start();
    try {
      return await query;
    } finally {
      this.loadingService.stop();
    }
  }

  /**
   * Carica i dati dal database applicando i filtri opzionali.
   */
  async loadData(additionalFilters?: Record<string, any>): Promise<void> {
    try {
      this.loadingSubject.next(true);
      this.errorSubject.next(null);

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        this.dataSubject.next([]);
        return;
      }

      let query = this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId);

      if (additionalFilters) {
        Object.entries(additionalFilters).forEach(([key, val]) => {
          if (val !== null && val !== undefined) {
            query = query.eq(key, val);
          }
        });
      }

      const { data, error } = await this.run<T[]>(query);

      if (error) throw error;

      this.dataSubject.next(data ?? []);
    } catch (error: any) {
      this.handleError('loadData', error);
      this.dataSubject.next([]);
    } finally {
      this.loadingSubject.next(false);
    }
  }

  /**
   * Crea un nuovo record.
   */
  async create(item: Partial<T>): Promise<T | null> {
    try {
      this.loadingSubject.next(true);
      this.errorSubject.next(null);

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return null;

      const payload = {
        ...item,
        restaurant_id: restaurantId,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      } as any;

      const { data, error } = await this.run<T>(
        this.supabaseService.getSupabaseClient()
          .from(this.getTableName())
          .insert(payload)
          .select()
          .single()
      );

      if (error) throw error;

      await this.loadData(); // refresh
      return data;
    } catch (error: any) {
      this.handleError('create', error);
      return null;
    } finally {
      this.loadingSubject.next(false);
    }
  }

  /**
   * Aggiorna un record esistente.
   */
  async update(id: string, updates: Partial<T>): Promise<boolean> {
    try {
      this.loadingSubject.next(true);
      this.errorSubject.next(null);

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return false;

      const { error } = await this.run<never>(
        this.supabaseService.getSupabaseClient()
          .from(this.getTableName())
          .update({ ...updates, updated_at: new Date().toISOString() } as any)
          .eq('id', id)
          .eq('restaurant_id', restaurantId)
      );

      if (error) throw error;

      await this.loadData(); // refresh
      return true;
    } catch (error: any) {
      this.handleError('update', error);
      return false;
    } finally {
      this.loadingSubject.next(false);
    }
  }

  /**
   * Elimina un record.
   */
  async delete(id: string): Promise<boolean> {
    try {
      this.loadingSubject.next(true);
      this.errorSubject.next(null);

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return false;

      const { error } = await this.run<never>(
        this.supabaseService.getSupabaseClient()
          .from(this.getTableName())
          .delete()
          .eq('id', id)
          .eq('restaurant_id', restaurantId)
      );

      if (error) throw error;

      await this.loadData(); // refresh
      return true;
    } catch (error: any) {
      this.handleError('delete', error);
      return false;
    } finally {
      this.loadingSubject.next(false);
    }
  }

  /**
   * Ottiene l'ID del ristorante corrente basandosi sul contesto autenticato.
   * Si affida completamente ad AuthService (già ottimizzato).
   */
  protected async getCurrentRestaurantId(): Promise<string | null> {
    return this.authService.getCurrentStaffRestaurantId();
  }

  /**
   * Osservabile che emette l'ID del ristorante corrente (reattivo).
   */
  protected getCurrentRestaurantId$(): Observable<string | null> {
    return this.authService.currentContext$.pipe(
      switchMap(() => from(this.getCurrentRestaurantId()))
    );
  }

  /**
   * Resetta i dati in memoria e gli errori.
   */
  clearCache(): void {
    this.dataSubject.next([]);
    this.errorSubject.next(null);
  }

  /**
   * Ottiene un record per ID dai dati già caricati.
   */
  getById(id: string): Observable<T | null> {
    return this.data$.pipe(
      map(items => items.find(item => (item as any).id === id) || null)
    );
  }

  /**
   * Resetta l'errore corrente.
   */
  clearError(): void {
    this.errorSubject.next(null);
  }

  /**
   * Gestione centralizzata degli errori.
   */
  protected handleError(method: string, error: any): void {
    console.error(`Error in ${method}:`, error);
    const msg = this.mapErrorMessage(error);
    this.errorSubject.next(msg);
  }

  /**
   * Mappa errori comuni a messaggi leggibili.
   */
  private mapErrorMessage(error: any): string {
    if (error?.code === '23505') return 'Elemento già esistente';
    if (error?.code === '23503') return 'Riferimento non valido';
    if (error?.message?.includes('network')) return 'Errore di connessione';
    return error?.message || 'Errore sconosciuto';
  }

  /**
   * Getter per i dati correnti.
   */
  get data(): T[] {
    return this.dataSubject.value;
  }

  /**
   * Espone il client Supabase per query personalizzate nei servizi figli.
   */
  public getSupabaseClientPublic() {
    return this.supabaseService.getSupabaseClient();
  }
}